import React, { Component } from 'react';
import cx from 'classnames';
import NewsItem from './NewsItem';
import NewsLoading from './NewsLoading';

import styles from './styles/NewsList.css';

export default class NewsList extends Component {
  componentWillMount() {
    const { category, fetchNews } = this.props;
    fetchNews(category);
  }
  
  getMore() {
    const { category, fetchMoreNews } = this.props;
    fetchMoreNews(category);
  }
  
  render() {
    const { news, category } = this.props;
    
    if (news && news.fetching) {
      return <NewsLoading />
    }
    
    if (!news || !news.list || !news.list.length) return (
      <div className={styles.more}>
        未找到<span className='text-primary'>{category}</span>相关新闻
      </div>
    );
    
    const allKeywords = news.list.reduce((prev, item) => {
      eval(item.keywords || []).forEach(({ name }) => {
        prev[name] = name;
      });
      
      return prev;
    }, {});
    
    const items = news.list.map((d, i) => <NewsItem {...d} key={i}/>)
    
    let more = null;
    
    if (news.nomore) {
      more = (
        <div className={styles.more}>
          没有更多的新闻
        </div>
      )
    } else if (news.more) {
      more = <NewsLoading />
    } else {
      more = (
        <div className={styles.more} onClick={ () => this.getMore()}>
          点击加载更多
        </div>
      )
    }
    
    return (
      <div className={styles.container}>
        <div className={cx('input-group input-group-sm', styles.search)}>
          <input type='text' className='form-control' />
          <span className='input-group-btn'>
            <button className='btn btn-default'>
              <span className='glyphicon glyphicon-search'></span>
            </button>
          </span>
        </div>
        <div className={styles.allkeywords}>
          { ['全部'].concat(Object.keys(allKeywords).slice(0, 10)).map(key => <span key={key} className={cx({[styles.active]: key === '全部'})}>{key}</span>) }
        </div>
        <div className={styles.news}>
          {items}
        </div>
        {more}
      </div>
    );
  }
}


