import React, { Component } from 'react';
import { bindActionCreators } from 'redux';
import { connect } from 'react-redux';
import * as actions from '../actions';
import cx from 'classnames';
import { stream, on, scan } from 'flyd';
import takeUntil from 'flyd/module/takeUntil';
import now from 'performance-now';

import styles from './styles/SwipeViews.css';

class SwipeViews extends Component {
  constructor(props) {
    super(props);
    
    this.touchStart$ = stream();
    this.touchMove$ = stream();
    this.touchEnd$ = stream();
    
    on(start => {
      const { dispatch, index, offset, children } = this.props;
      
      const move$ = takeUntil(this.touchMove$, this.touchEnd$);
      
      const startTime = now();
      
      on(d => {
        const offset = (start - d) / window.innerWidth;
        const count = React.Children.count(children);
        
        if (index >= count - 1 && offset > 0) return;
        if (index == 0 && offset < 0) return;
        
        if (offset < 0.2 && offset > - 0.2) return;
        
        dispatch(actions.move(offset));
        
      }, move$);
      
      on(d => {
        const endTime = now();
        const offset = (start - move$()) / window.innerWidth;
        const speed = offset / (endTime - startTime);

        if ((speed > 0.001 || speed < -0.001) 
          && (offset > 0.2 || offset < - 0.2)
        ) {
          const count = React.Children.count(children);
        
          if (index >= count - 1 && offset > 0) return;
          if (index == 0 && offset < 0) return;
          
          dispatch(actions.transitionTo(index + (speed > 0 ? 1 : -1)));
        }
        
        dispatch(actions.moveEnd());
      }, move$.end);
      
    }, this.touchStart$)
    
  }
  
  transitionTo(index) {
    this.props.dispatch(actions.transitionTo(index));
  }
  
  shouldComponentUpdate(nextProps) {
    return nextProps.index !== this.props.index 
    || nextProps.offset !== this.props.offset 
    || nextProps.animate !== this.props.animate
    || nextProps.children !== this.props.children
  }

  componentWillUnmount() {
    this.touchStart$.end(true);
    this.touchMove$.end(true);
    this.touchEnd$.end(true);
  }
  
  render() {
    const { index, offset, animate, children } = this.props;
    const count = React.Children.count(children);
    
    const views = React.Children.map(children, (child, i) => (
      <div 
        key={i}
        style={{ width: `${100 / count}%` }}
        className={styles.view}
      >
        {child}
      </div>
    ))
    
    const transform = `translateX(-${(index + offset) * 100 / count}%)`;
    
    return (
      <div className={styles.container}>
        <div 
          className={styles.content} 
          style={{ 
            width: 100 * children.length,
            transform: transform,
            WebkitTransform: transform,
            transitionProperty: animate ? 'all' : 'none',
            width: `${count * 100}%`
          }}
          onTouchStart={(event) => this.touchStart$(event.changedTouches[0].clientX)}
          onTouchMove={(event) => this.touchMove$(event.changedTouches[0].clientX)}
          onTouchEnd={(event) => this.touchEnd$(event.changedTouches[0].clientX)}
        >
          {views}
        </div>
      </div>
    )
  }
}

function select(state) {
  return {
    ...state.swipe
  }
}

export default connect(select)(SwipeViews);




