import React, { Component } from 'react';
import cx from 'classnames';
import { addClass, removeClass } from 'fbjs/lib/CSSCore';

import styles from './styles/NewsHistory.css';

export default class NewsHistory extends Component {
  shouldComponentUpdate(nextProps) {
    return nextProps.show !== this.props.show 
      || nextProps.histories !== this.props.histories;
  }
  
  componentDidMount() {
    setTimeout(() => {
      addClass(this.refs.container, styles.show);
    }, 0);
  }
  
  hideHistory() {
    removeClass(this.refs.container, styles.show);
    setTimeout(() => {
      this.props.hideHistory();
    }, 300);
  }
  
  render() {
    const { histories } = this.props;
    
    const groups = histories.reduce((prev, item) => {
      const year = prev[item[0]] || [];
      
      return { ...prev, [item[0]]: year.concat([item[1]]) }
      
    }, {});
    
    const sorted = Object.keys(groups).sort((a, b) => +b - +a);
    
    const years = sorted.map(year => {
      return (
          <li key={year}>
            <span className={styles.year}>
              {year}
              <span className={cx('glyphicon glyphicon-ok pull-right', styles.option)}></span>
            </span>
            <ul className='list-group'>
              { groups[year].map(month => {
                return (
                  <li key={month} className='list-group-item'>
                    <span className={styles.month}>
                      {year}年{month}月
                      <span className={cx('glyphicon glyphicon-ok pull-right', styles.option)}></span>
                    </span>
                  </li>
                )
              })}
            </ul>
          </li>
      )
    });
    
    return (
      <div className={cx(styles.history)} ref='container'>
        <a href='#' onClick={() => this.hideHistory()} className={styles.close}>
          <span className='glyphicon glyphicon-remove'></span>
        </a>
        <div className={styles.scroll}>
          <ul>
            {years}
          </ul>
          <button className='btn btn-primary btn-block'>
            查看更早新闻
          </button>
        </div>
      </div>
    )
  }
}


