import { MOVE, MOVE_END, TRANSITION_TO } from '../constants/ActionTypes';

const initialState = {
  index: 0,
  offset: 0,
  animate: true
}

export default function swipe(state = initialState, action) {
  switch (action.type) {
    case MOVE:
      const { offset } = action;
      
      return {
        index: state.index,
        offset,
        animate: false
      };
    case MOVE_END:
      const next = state.index + Math.round(state.offset);
      
      return {
        index: next,
        offset: 0,
        animate: true
      }
    case TRANSITION_TO:
      const { index } = action;
      
      return {
        index,
        offset: 0,
        animate: true  
      }
    default:
      return state;
  }
}


