import React, { Component } from 'react';
import { bindActionCreators } from 'redux';
import { connect } from 'react-redux';
import cx from 'classnames';
import SwipeViews from '../swipe/components/SwipeViews';

import 'bootstrap/less/bootstrap.less';
import styles from './styles/global.css';
import * as categoryActions from '../actions/categories';
import * as swipeActions from '../swipe/actions';
import * as newsActions from '../actions/news';
import * as newsHistoryActions from '../actions/newsHistory';
import NewsList from '../components/NewsList';
import NewsHistory from '../components/NewsHistory';

class NewsApp extends Component {
  componentWillMount() {
    this.props.dispatch(categoryActions.fetchCategories());
  }
  
  tapMenu(i) {
    this.props.dispatch(swipeActions.transitionTo(i));
  }
  
  showHistory() {
    this.props.dispatch(newsHistoryActions.showHistory());
  }
  
  render() {
    const { dispatch, categories, news, swipe: { index }, newsHistory } = this.props;
    
    let newsDialog = null;
    
    if (newsHistory.show) {
      newsDialog = <NewsHistory {...newsHistory} {...bindActionCreators(newsHistoryActions, dispatch)}/>
    }
    
    return (
      <div className={styles.app}>
        <div className={cx('navbar', 'navbar-fixed-top', 'navbar-inverse', styles.navbar)}>
          <div className='navbar-header'>
            <ul className={cx(styles.nav)}>
              { categories.map((d, i) => (
                <li className={cx({[styles.active]: i === index})} key={i}>
                  <a href='#' onClick={() => this.tapMenu(i)}>{d}</a>
                </li>)) }
            </ul>
          </div>
          <a className={cx(styles.date)} href='#' onClick={ () => this.showHistory() }>
            <span className='glyphicon glyphicon-time' style={{ fontSize: '18px' }}></span>
          </a>
        </div>
        <SwipeViews>
          { categories.map((d, i) => (
            <NewsList 
              key={i} 
              category={d} 
              news={news[d]} 
              {...bindActionCreators(newsActions, dispatch)}
            />
          )) }
        </SwipeViews>
        {newsDialog}  
      </div>
    );
  }
}

function select(state) {
  return {
    categories: state.categories,
    swipe: state.swipe,
    news: state.news,
    newsHistory: state.newsHistory
  };
}

export default connect(select)(NewsApp);


