import React, { Component } from 'react';
import cx from 'classnames';

import styles from './styles/NewsList.css';

export default class NewsItem extends Component {
  constructor(props) {
    super(props);
    this.state = {
      clip: true
    }
  }
  
  toggle() {
    this.setState({
      clip: !this.state.clip
    })
  }
  
  render() {
    const { title, content, timestamp, source, url, keywords } = this.props;
    return (
      <div className={cx('media', styles.item)}>
        <div className='media-body'>
          <h4 class='media-heading'>
            {title}
          </h4>
          <div className={styles.info}>
            <span>{new Date(timestamp).toLocaleDateString()}</span>
            <a href={`http://${url}`}>{source}</a>
            <span className={cx('glyphicon glyphicon-thumbs-up', styles.good)}></span>
          </div>
          <div className={styles.keywords}>
            { (eval(keywords) || []).map(({ name, weight }, i) => {
              return <span key={i} style={{ color: `rgb(64, 128, ${Math.round(128 + 64 * weight)})`}}>{name}</span>
            })}
          </div>
          <p 
            className={cx( styles.content, { [styles['content-clip']]: this.state.clip } )} 
            onClick={ () => this.toggle() }
          >
            {content}
          </p>
        </div>
      </div>
    )
  }
}


