import { SHOW_HISTORY, HIDE_HISTORY } from '../constants/ActionTypes';

const initialState = {
  show: false,
  histories: [
    ['2016', '05'],
    ['2016', '04'],
    ['2016', '03'],
    ['2016', '02'],
    ['2016', '01'],
    ['2015', '12'],
    ['2015', '11'],
    ['2015', '10'],
    ['2015', '09'],
    ['2015', '08'],
    ['2015', '07'],
    ['2015', '06'],
    ['2015', '05'],
    ['2015', '04'],
    ['2015', '03'],
    ['2015', '02'],
    ['2015', '01'],
  ]
}

export default function newsHistory(state = initialState, action) {
  switch (action.type) {
    case SHOW_HISTORY:
      return {
        ...state,
        show: true
      }
    case HIDE_HISTORY:
      return {
        ...state,
        show: false
      }
    default:
      return state;
  }
}


