
import React, { Component } from 'react';
import { Provider } from 'react-redux';
import NewsApp from './NewsApp';

export default class Root extends Component {
  render() {
    const { store } = this.props;
    return (
      <Provider store={store}>
        <NewsApp />
      </Provider>
    );
  }
}


