import { MOVE, MOVE_END, TRANSITION_TO } from '../constants/ActionTypes';

export function move(offset) {
  return {
    type: MOVE,
    offset
  }
}

export function moveEnd() {
  return {
    type: MOVE_END
  }
}

export function transitionTo(index) {
  return {
    type: TRANSITION_TO,
    index
  }
}


