import { REQUEST_NEWS, NEWS_RECEIVED, REQUEST_MORE_NEWS, MORE_NEWS_RECEIVED } from '../constants/ActionTypes';

export function fetchNews(category) {
  return (dispatch) => {
    dispatch(requestNews(category));
    
    setTimeout(() => {
      dispatch(receiveNews(category));
    }, 800);
  }
}

export function fetchMoreNews(category) {
  return (dispatch) => {
    dispatch(requestMoreNews(category));
    
    setTimeout(() => {
      dispatch(receiveMoreNews(category));
    }, 800);
  }
}

function requestNews(category) {
  return {
    type: REQUEST_NEWS,
    category: category
  }
}

function requestMoreNews(category) {
  return {
    type: REQUEST_MORE_NEWS,
    category: category
  }
}

function receiveNews(category) {
  if (category !== '旅游') {
    return {
      type: NEWS_RECEIVED,
      list: [],
      category: category
    }  
  }
  
  return {
    type: NEWS_RECEIVED,
    list: require('../data/news.json'),
    category: category
  }
}

function receiveMoreNews(category) {
  return {
    type: MORE_NEWS_RECEIVED,
    list: [],
    category: category
  }
}




