import { NEWS_RECEIVED, REQUEST_NEWS, REQUEST_MORE_NEWS, MORE_NEWS_RECEIVED } from '../constants/ActionTypes';

export default function news(state = {}, action) {
  let news = state[action.category];
  
  switch (action.type) {
    case NEWS_RECEIVED:
      return {
        ...state,
        [action.category]: {
          list: action.list,
          fetching: false,
          more: false
        }
      }
    case REQUEST_NEWS:
      return {
        ...state,
        [action.category]: {
          list: [],
          fetching: true,
          more: false
        }
      }
    case REQUEST_MORE_NEWS:
      return {
        ...state,
        [action.category]: {
          ...news,
          more: true
        }
      }
    case MORE_NEWS_RECEIVED:
      return {
        ...state,
        [action.category]: {
          ...news,
          list: news.list.concat(action.list),
          nomore: action.list.length === 0,
          more: false
        }
      }
    default:
      return state;
    }
}


